-- в”Ђв”Ђ Misskey в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$Misskey is a free, open-source, decentralized microblogging platform in the Fediverse that lets anyone run their own federated social network instance.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2014, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Japan$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$Japanese$q$]::text[],
  seo_title = COALESCE($q$Misskey Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Misskey review: a free, open-source, decentralized microblogging platform in the Fediverse. Learn its features, self-hosting, and alternatives like Mastodon.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Misskey is a free and open-source, decentralized microblogging and social networking platform that is part of the Fediverse, the network of interconnected servers that communicate using the ActivityPub protocol. It was created in 2014 by Japanese software engineer Eiji Shinoda, known online as syuilo, who originally built it as a BBS-style internet forum while still a high school student. After Shinoda introduced a timeline feature, the project evolved into the microblogging platform it is known as today. In 2018, Misskey added support for the ActivityPub protocol, transforming it from a standalone social platform into a federated one capable of interacting with other ActivityPub-compatible software such as Mastodon and Pleroma. The flagship and largest Misskey instance, misskey.io, launched on April 15, 2019, and became a major hub for Japanese-language Fediverse users; Misskey saw a significant surge in adoption in 2023 as users looked for Twitter/X alternatives, with misskey.io's registered accounts reportedly more than doubling from roughly 180,000 in July 2023 to about 370,000 by August 2023. Misskey's source code is released under the AGPLv3 open-source license and is developed primarily in TypeScript on both the Node.js backend and the frontend, coordinated through the misskey-dev organization on GitHub. Because Misskey is decentralized, there is no single company or central server that all users must join; instead, anyone can self-host their own Misskey instance and communicate with users on other Misskey instances or other Fediverse platforms, similar in spirit to email federation. On Misskey, user posts are called notes, which support a much longer character limit than traditional microblogging (commonly up to 3,000 characters by default, and configurable per instance), along with attachments including images, videos, audio, and polls. Distinctive features that set Misskey apart from Mastodon and other Fediverse software include custom emoji reactions on posts (rather than simple likes), channels for topic-based discussion spaces, antennas that let users build custom keyword- or account-based timelines, a built-in Drive feature for managing uploaded files, extensive UI theming and customization, configurable user roles, and a responsive web interface built as a Progressive Web App. Because Misskey is free, open-source, self-hosted software rather than a single commercial product, there is no vendor pricing model; individuals or organizations that want to run an instance are responsible for their own server hosting costs, while joining an existing public instance like misskey.io is typically free to end users. Misskey's target audience includes privacy- and decentralization-minded social media users, Fediverse enthusiasts, Japanese-language online communities where it has particularly strong adoption, and developers interested in running or customizing their own federated social platform. Its main competitors and closely related alternatives include Mastodon (the most widely known Fediverse microblogging platform), Pleroma, Akkoma, and forks of Misskey itself such as Sharkey and Firefish/Calckey, with Misskey differentiating itself through its distinctive reaction-based interaction model, extensive customization options, and strong roots in the Japanese Fediverse community.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'bbcea426-8b22-4fd5-96ad-4e11c6da8bd2';

