INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('71c7930e-f978-4543-907b-1d45df9c86d7', $q$Strict two-participant rooms$q$, $q$Each room is limited to exactly two people, a deliberate design choice for private, secure 1:1 conversations rather than group meetings.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('71c7930e-f978-4543-907b-1d45df9c86d7', $q$Peer-to-peer WebRTC transport$q$, $q$Video and audio flow directly between the two browsers using WebRTC, avoiding a central relay server for lower latency.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('71c7930e-f978-4543-907b-1d45df9c86d7', $q$No downloads or plugins$q$, $q$Runs entirely in the browser; participants join with just a link and a display name.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('71c7930e-f978-4543-907b-1d45df9c86d7', $q$End-to-end encrypted calls$q$, $q$Media is encrypted in transit, keeping conversations private between the two participants.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('71c7930e-f978-4543-907b-1d45df9c86d7', $q$Self-hostable$q$, $q$The full source is open source and can be deployed on a private server via Node.js/Docker for complete data control.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('71c7930e-f978-4543-907b-1d45df9c86d7', $q$Lightweight interface$q$, $q$A minimal, distraction-free UI tuned specifically for one-to-one calling rather than a full meeting toolbox.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('71c7930e-f978-4543-907b-1d45df9c86d7', $q$Free public demo$q$, $q$c2c.mirotalk.com offers a hosted instance to try the app without setting up a server.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('71c7930e-f978-4543-907b-1d45df9c86d7', $q$Completely free and open source under AGPLv3$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('71c7930e-f978-4543-907b-1d45df9c86d7', $q$Simple, no-download browser-based joining flow$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('71c7930e-f978-4543-907b-1d45df9c86d7', $q$Peer-to-peer architecture keeps media data off third-party servers$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('71c7930e-f978-4543-907b-1d45df9c86d7', $q$Self-hostable for full data control and privacy$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('71c7930e-f978-4543-907b-1d45df9c86d7', $q$Focused, uncluttered design for 1:1 calls$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('71c7930e-f978-4543-907b-1d45df9c86d7', $q$Hard two-participant limit means it cannot be used for group meetings$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('71c7930e-f978-4543-907b-1d45df9c86d7', $q$No official vendor support, SLA, or account management, being community-maintained$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('71c7930e-f978-4543-907b-1d45df9c86d7', $q$Requires technical setup (server, Docker/Node.js) for self-hosting beyond the demo$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('71c7930e-f978-4543-907b-1d45df9c86d7', $q$Fewer built-in collaboration tools (no whiteboard or advanced recording) than the P2P or SFU editions$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('71c7930e-f978-4543-907b-1d45df9c86d7', $q$Documentation and support rely mainly on GitHub issues and community channels$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('71c7930e-f978-4543-907b-1d45df9c86d7', $q$What is MiroTalk C2C used for?$q$, $q$It is used for private, one-to-one cam-to-cam video calls, such as consultations, interviews, tutoring, or personal conversations, where exactly two people need a secure direct connection.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('71c7930e-f978-4543-907b-1d45df9c86d7', $q$Is MiroTalk C2C free?$q$, $q$Yes, it is free and open source under the AGPLv3 license, and a public demo is available at c2c.mirotalk.com.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('71c7930e-f978-4543-907b-1d45df9c86d7', $q$Can more than two people join a MiroTalk C2C room?$q$, $q$No, each room is deliberately limited to two participants for maximum privacy and simplicity.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('71c7930e-f978-4543-907b-1d45df9c86d7', $q$How is MiroTalk C2C different from MiroTalk P2P and MiroTalk SFU?$q$, $q$MiroTalk P2P supports small multi-person rooms and MiroTalk SFU supports large, scalable group conferences using a server-based SFU architecture, while C2C is purpose-built only for two-person calls.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('71c7930e-f978-4543-907b-1d45df9c86d7', $q$Do I need to install anything to use MiroTalk C2C?$q$, $q$No, it runs entirely in a modern web browser using WebRTC, with no downloads, plugins, or accounts required.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('71c7930e-f978-4543-907b-1d45df9c86d7', $q$Can I self-host MiroTalk C2C?$q$, $q$Yes, the source code is publicly available on GitHub and can be self-hosted on your own server using Node.js and Docker.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('71c7930e-f978-4543-907b-1d45df9c86d7', $q$Private consultations$q$, $q$Professionals such as coaches, consultants, or advisors can share a direct link for a secure one-to-one video meeting.$q$, $q$Independent professionals and consultants$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('71c7930e-f978-4543-907b-1d45df9c86d7', $q$Remote interviews$q$, $q$Recruiters or journalists can conduct one-to-one video interviews without requiring the other party to create an account or install software.$q$, $q$Recruiters and interviewers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('71c7930e-f978-4543-907b-1d45df9c86d7', $q$Personal peer-to-peer calls$q$, $q$Individuals who want a private, encrypted alternative to mainstream video call apps for casual 1:1 conversations.$q$, $q$Privacy-conscious individuals$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('71c7930e-f978-4543-907b-1d45df9c86d7', $q$Open Source (Self-Hosted)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full source code","Self-host on your own server","Unlimited two-person rooms","AGPLv3 license"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('71c7930e-f978-4543-907b-1d45df9c86d7', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$MiroTalk C2C is a free, open-source WebRTC application purpose-built for one-to-one, cam-to-cam video calls. It is part of the MiroTalk WebRTC family of self-hosted video calling apps created by developer Miroslav Pejic, sitting alongside MiroTalk P2P (multi-participant room calls) and MiroTalk SFU (scalable group conferencing).$q$, $q$Unlike general-purpose video meeting tools, MiroTalk C2C intentionally caps each room at two participants, framing this as a security and simplicity feature rather than a limitation, and is aimed at direct, private 1:1 conversations rather than team meetings.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('71c7930e-f978-4543-907b-1d45df9c86d7', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Because MiroTalk C2C uses direct peer-to-peer WebRTC connections, audio and video travel straight between the two participants' browsers rather than through a central media server, which reduces latency and keeps call data off third-party infrastructure.$q$, $q$Joining a call requires no installation, plugin, or account: users open a room link in a modern browser, enter a display name, and connect. The project emphasizes end-to-end encrypted transport for privacy-sensitive use cases such as consultations or interviews.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('71c7930e-f978-4543-907b-1d45df9c86d7', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$MiroTalk C2C is free and open source under the AGPLv3 license. There is no subscription or per-seat fee from the project itself; the only cost is whatever server hosting an operator chooses if they self-host their own instance rather than using the public demo.$q$, $q$A public demo instance is available directly at c2c.mirotalk.com, so casual users can try the tool without any deployment work, while organizations wanting full control typically self-host the open-source code on their own infrastructure.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('71c7930e-f978-4543-907b-1d45df9c86d7', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('71c7930e-f978-4543-907b-1d45df9c86d7', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0650c50c-6e38-47ff-9b1c-ad5c7004e35a', $q$Peer-to-peer video and audio$q$, $q$Direct WebRTC connections between participants' browsers minimize latency and avoid routing media through a central server.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0650c50c-6e38-47ff-9b1c-ad5c7004e35a', $q$Screen sharing up to 8K/60fps$q$, $q$High-resolution screen sharing for presentations, demos, and document review.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0650c50c-6e38-47ff-9b1c-ad5c7004e35a', $q$Collaborative whiteboard$q$, $q$A built-in interactive whiteboard for real-time drawing and explanation during calls.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0650c50c-6e38-47ff-9b1c-ad5c7004e35a', $q$Public and private chat$q$, $q$In-call chat with emoji support and saved message history alongside video.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0650c50c-6e38-47ff-9b1c-ad5c7004e35a', $q$Meeting recording$q$, $q$Records screen, webcam, and audio for later reference or sharing.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0650c50c-6e38-47ff-9b1c-ad5c7004e35a', $q$Encrypted file sharing$q$, $q$File transfer secured using DTLS encryption between participants.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0650c50c-6e38-47ff-9b1c-ad5c7004e35a', $q$No download or login required$q$, $q$Runs entirely in the browser; participants join instantly via a room link.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0650c50c-6e38-47ff-9b1c-ad5c7004e35a', $q$Self-hosted deployment$q$, $q$Fully open-source code that can be deployed on a private server for complete data ownership.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0650c50c-6e38-47ff-9b1c-ad5c7004e35a', $q$Free and open source under AGPLv3$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0650c50c-6e38-47ff-9b1c-ad5c7004e35a', $q$Low-latency peer-to-peer calls with no central media server$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0650c50c-6e38-47ff-9b1c-ad5c7004e35a', $q$Rich built-in toolset: whiteboard, chat, screen share, recording$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0650c50c-6e38-47ff-9b1c-ad5c7004e35a', $q$No installation or account needed to join a call$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0650c50c-6e38-47ff-9b1c-ad5c7004e35a', $q$Full data control when self-hosted$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0650c50c-6e38-47ff-9b1c-ad5c7004e35a', $q$Peer-to-peer architecture scales poorly beyond small groups compared to SFU-based tools$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0650c50c-6e38-47ff-9b1c-ad5c7004e35a', $q$No official managed hosting or enterprise SLA from the core project$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0650c50c-6e38-47ff-9b1c-ad5c7004e35a', $q$Requires server setup and maintenance knowledge to self-host$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0650c50c-6e38-47ff-9b1c-ad5c7004e35a', $q$Community-driven support rather than dedicated customer service$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0650c50c-6e38-47ff-9b1c-ad5c7004e35a', $q$Large groups should use MiroTalk SFU instead, adding a decision step for new users$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0650c50c-6e38-47ff-9b1c-ad5c7004e35a', $q$What is MiroTalk P2P best used for?$q$, $q$Small-group video calls, typically up to around eight participants, where low latency and self-hosted privacy matter more than large-scale scalability.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0650c50c-6e38-47ff-9b1c-ad5c7004e35a', $q$Is MiroTalk P2P free?$q$, $q$Yes, it is free and open source under the AGPLv3 license, self-hostable on your own server at no licensing cost.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0650c50c-6e38-47ff-9b1c-ad5c7004e35a', $q$How is MiroTalk P2P different from MiroTalk SFU?$q$, $q$MiroTalk P2P connects participants directly to each other (peer-to-peer), which is efficient for small rooms, while MiroTalk SFU routes media through a server for unlimited participants and better scalability in larger meetings.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0650c50c-6e38-47ff-9b1c-ad5c7004e35a', $q$Do I need an account to join a MiroTalk P2P call?$q$, $q$No, participants can join instantly through a browser using a room link and a display name.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0650c50c-6e38-47ff-9b1c-ad5c7004e35a', $q$Can I record meetings in MiroTalk P2P?$q$, $q$Yes, it includes built-in recording of screen, webcam, and audio.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0650c50c-6e38-47ff-9b1c-ad5c7004e35a', $q$Can I self-host MiroTalk P2P?$q$, $q$Yes, the source code is available on GitHub and can be deployed on your own server using Node.js and Docker.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0650c50c-6e38-47ff-9b1c-ad5c7004e35a', $q$Small team meetings$q$, $q$Teams that want a free, self-hosted Zoom alternative for quick calls with chat and screen sharing.$q$, $q$Small businesses and remote teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0650c50c-6e38-47ff-9b1c-ad5c7004e35a', $q$Client presentations$q$, $q$Consultants and freelancers sharing screens and whiteboards with a small number of clients.$q$, $q$Freelancers and consultants$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0650c50c-6e38-47ff-9b1c-ad5c7004e35a', $q$Privacy-focused organizations$q$, $q$Groups that need full control over where call data is processed and stored by self-hosting their own instance.$q$, $q$Privacy-conscious teams and developers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0650c50c-6e38-47ff-9b1c-ad5c7004e35a', $q$Open Source (Self-Hosted)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full source code","Self-host on your own server","Small-group P2P rooms","Screen share, chat, whiteboard, recording","AGPLv3 license"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0650c50c-6e38-47ff-9b1c-ad5c7004e35a', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$MiroTalk P2P is the original, free and open-source edition of the MiroTalk WebRTC video conferencing project, built on a peer-to-peer architecture where participants' browsers connect directly to each other rather than through a central media server.$q$, $q$It is positioned as a self-hosted alternative to Zoom, Google Meet, and Microsoft Teams for small-group video calls, chat, screen sharing, and whiteboarding, with no download, plugin, or account required to join a room.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0650c50c-6e38-47ff-9b1c-ad5c7004e35a', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The app supports webcam streaming and screen sharing up to 8K resolution at 60fps, a real-time collaborative whiteboard, public and private in-call chat with emoji support and message history, encrypted file sharing, and meeting recording of screen, webcam, and audio.$q$, $q$Because it uses direct peer-to-peer WebRTC connections rather than a server-based relay, rooms perform best with a small number of concurrent participants, roughly in the range of two to eight, rather than large webinars.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0650c50c-6e38-47ff-9b1c-ad5c7004e35a', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$MiroTalk P2P is free and open source under the AGPLv3 license; anyone can self-host the software on their own server at no licensing cost, paying only for their own infrastructure.$q$, $q$There is no official managed SaaS subscription for this specific edition; users who want a larger-scale or managed deployment typically move to the MiroTalk SFU edition or a third-party licensed build.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0650c50c-6e38-47ff-9b1c-ad5c7004e35a', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0650c50c-6e38-47ff-9b1c-ad5c7004e35a', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b7e3dfde-b66e-49af-b87b-8a41ddca3f88', $q$SFU (mediasoup) architecture$q$, $q$Media streams are relayed through a central server rather than connecting every participant directly, enabling much larger meetings than pure P2P.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b7e3dfde-b66e-49af-b87b-8a41ddca3f88', $q$Unlimited rooms and participants$q$, $q$No hard cap on concurrent rooms or call duration, suited to webinars and larger group conferences.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b7e3dfde-b66e-49af-b87b-8a41ddca3f88', $q$8K/60fps screen and webcam sharing$q$, $q$High-resolution video and screen sharing with echo cancellation and noise suppression.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b7e3dfde-b66e-49af-b87b-8a41ddca3f88', $q$RTMP streaming$q$, $q$Broadcast meetings out to external platforms via RTMP for larger audiences.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b7e3dfde-b66e-49af-b87b-8a41ddca3f88', $q$AI avatars and ChatGPT integration$q$, $q$Built-in AI features including avatars and ChatGPT integration for meetings.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b7e3dfde-b66e-49af-b87b-8a41ddca3f88', $q$Collaborative whiteboard$q$, $q$Real-time shared whiteboard for group brainstorming and explanation.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b7e3dfde-b66e-49af-b87b-8a41ddca3f88', $q$Meeting recording$q$, $q$Record screen, webcam, and audio directly from the browser.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b7e3dfde-b66e-49af-b87b-8a41ddca3f88', $q$Self-hosted deployment$q$, $q$Full source code and Docker-based install scripts for deploying on your own cloud server.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b7e3dfde-b66e-49af-b87b-8a41ddca3f88', $q$Scales to unlimited participants far better than peer-to-peer video tools$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b7e3dfde-b66e-49af-b87b-8a41ddca3f88', $q$Free and open source under AGPLv3, with an optional commercial license for alternative terms$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b7e3dfde-b66e-49af-b87b-8a41ddca3f88', $q$Rich feature set including RTMP streaming, AI avatars, and ChatGPT integration$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b7e3dfde-b66e-49af-b87b-8a41ddca3f88', $q$No download or login required for participants to join$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b7e3dfde-b66e-49af-b87b-8a41ddca3f88', $q$Full data ownership and no vendor lock-in when self-hosted$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b7e3dfde-b66e-49af-b87b-8a41ddca3f88', $q$Self-hosting an SFU server requires more technical setup and server resources than the P2P edition$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b7e3dfde-b66e-49af-b87b-8a41ddca3f88', $q$No official managed cloud SaaS offering from the core open-source project$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b7e3dfde-b66e-49af-b87b-8a41ddca3f88', $q$Community-based support rather than guaranteed enterprise SLAs$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b7e3dfde-b66e-49af-b87b-8a41ddca3f88', $q$Advanced features like AI avatars and ChatGPT integration may require additional configuration or API keys$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b7e3dfde-b66e-49af-b87b-8a41ddca3f88', $q$Running large meetings reliably depends on adequately provisioned server infrastructure$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b7e3dfde-b66e-49af-b87b-8a41ddca3f88', $q$What makes MiroTalk SFU different from MiroTalk P2P?$q$, $q$MiroTalk SFU routes media through a central server using an SFU (mediasoup) architecture, which scales to unlimited participants, while MiroTalk P2P connects participants directly to each other and works best for small groups.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b7e3dfde-b66e-49af-b87b-8a41ddca3f88', $q$Is MiroTalk SFU free?$q$, $q$Yes, it is free and open source under the AGPLv3 license, and can be self-hosted at no licensing cost; a commercial license is also available for alternative licensing terms.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b7e3dfde-b66e-49af-b87b-8a41ddca3f88', $q$Can MiroTalk SFU be used for webinars?$q$, $q$Yes, its RTMP streaming support and unlimited participant capacity make it suitable for webinars and larger events, not just small meetings.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b7e3dfde-b66e-49af-b87b-8a41ddca3f88', $q$Does MiroTalk SFU require downloads or plugins?$q$, $q$No, it runs entirely in the browser using WebRTC, with no downloads, plugins, or logins required to join a call.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b7e3dfde-b66e-49af-b87b-8a41ddca3f88', $q$What is mediasoup and why does MiroTalk SFU use it?$q$, $q$Mediasoup is an open-source SFU library that MiroTalk SFU uses to efficiently relay media between many participants, enabling scalable group video conferencing.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b7e3dfde-b66e-49af-b87b-8a41ddca3f88', $q$Can I self-host MiroTalk SFU?$q$, $q$Yes, the full source code is on GitHub with documented Docker, Node.js, and Nginx setup scripts for deploying your own instance.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b7e3dfde-b66e-49af-b87b-8a41ddca3f88', $q$Webinars and online classes$q$, $q$Educators and businesses hosting larger group sessions that exceed what peer-to-peer tools can handle.$q$, $q$Educators and event organizers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b7e3dfde-b66e-49af-b87b-8a41ddca3f88', $q$Company-wide meetings$q$, $q$Organizations needing a scalable, self-hosted alternative to commercial video conferencing platforms.$q$, $q$Businesses and IT teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b7e3dfde-b66e-49af-b87b-8a41ddca3f88', $q$Live broadcasting$q$, $q$Streamers or organizations using RTMP output to broadcast meetings to external platforms.$q$, $q$Content creators and broadcasters$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b7e3dfde-b66e-49af-b87b-8a41ddca3f88', $q$Open Source (Self-Hosted)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full source code","Self-host on your own server","Unlimited rooms and participants","AGPLv3 license"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b7e3dfde-b66e-49af-b87b-8a41ddca3f88', $q$Commercial License$q$, $q$One-time fee (around $99 via marketplace listings)$q$, $q$One-time$q$, NULL, $q$["Alternative licensing terms outside AGPLv3","Full source code","Lifetime updates"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b7e3dfde-b66e-49af-b87b-8a41ddca3f88', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$MiroTalk SFU is the scalable group-conferencing edition of the open-source MiroTalk WebRTC project, built on a Selective Forwarding Unit (SFU) architecture using the mediasoup library rather than direct peer-to-peer connections.$q$, $q$This server-mediated design lets it support unlimited concurrent rooms and far more participants per meeting than the peer-to-peer MiroTalk P2P edition, positioning it as a self-hosted, open-source alternative to Zoom, Google Meet, and Microsoft Teams for larger conferences and webinars.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b7e3dfde-b66e-49af-b87b-8a41ddca3f88', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The platform offers webcam and screen sharing up to 8K at 60fps with echo cancellation and noise suppression, an interactive whiteboard, integrated chat, file sharing, and meeting recording, all running in the browser with no downloads or plugins.$q$, $q$More advanced capabilities aimed at events and broadcasting include RTMP streaming to external platforms, virtual backgrounds, ChatGPT integration, and AI avatars for participants.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b7e3dfde-b66e-49af-b87b-8a41ddca3f88', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$MiroTalk SFU is free and open source under the AGPLv3 license, allowing anyone to self-host it on their own server infrastructure at no licensing cost.$q$, $q$For teams that want alternative licensing terms outside AGPLv3's copyleft obligations, a commercial license has also been offered through third-party marketplaces such as CodeCanyon as a one-time purchase that includes full source code and lifetime updates.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b7e3dfde-b66e-49af-b87b-8a41ddca3f88', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b7e3dfde-b66e-49af-b87b-8a41ddca3f88', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2b43eeda-4ceb-459a-a73d-d764275698c6', $q$OAuth login with 50+ providers$q$, $q$Users can register and sign in via Google, Facebook, GitHub, Steam, and dozens of other OAuth providers.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2b43eeda-4ceb-459a-a73d-d764275698c6', $q$Markdown and BBCode support$q$, $q$Flexible post formatting options for different community preferences.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2b43eeda-4ceb-459a-a73d-d764275698c6', $q$Best-answer marking$q$, $q$Q&A-style categories let the community or moderators mark the best answer to a question.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2b43eeda-4ceb-459a-a73d-d764275698c6', $q$Unlimited nested categories$q$, $q$Build deep, organized category and subcategory structures for large communities.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2b43eeda-4ceb-459a-a73d-d764275698c6', $q$Edit history and revision tracking$q$, $q$Full history of post edits is preserved for transparency and moderation.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2b43eeda-4ceb-459a-a73d-d764275698c6', $q$Comprehensive moderation queue$q$, $q$Post approval workflows and content management tools for moderators.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2b43eeda-4ceb-459a-a73d-d764275698c6', $q$Banning by name, email, or IP$q$, $q$Granular banning tools to manage disruptive users.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2b43eeda-4ceb-459a-a73d-d764275698c6', $q$Attachment thumbnails$q$, $q$Automatic thumbnail generation for image and file attachments in posts.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2b43eeda-4ceb-459a-a73d-d764275698c6', $q$Completely free and open source with no licensing cost$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2b43eeda-4ceb-459a-a73d-d764275698c6', $q$Modern React-based frontend paired with a mature Django backend$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2b43eeda-4ceb-459a-a73d-d764275698c6', $q$Strong moderation and permission tooling out of the box$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2b43eeda-4ceb-459a-a73d-d764275698c6', $q$Wide OAuth provider support for easy user sign-up$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2b43eeda-4ceb-459a-a73d-d764275698c6', $q$Full control over hosting, data, and customization$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2b43eeda-4ceb-459a-a73d-d764275698c6', $q$Requires self-hosting and server management skills, unlike hosted forum SaaS products$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2b43eeda-4ceb-459a-a73d-d764275698c6', $q$Smaller ecosystem and plugin marketplace compared to Discourse$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2b43eeda-4ceb-459a-a73d-d764275698c6', $q$No official paid support tier or enterprise SLA from a vendor$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2b43eeda-4ceb-459a-a73d-d764275698c6', $q$Documentation and community size are more limited than larger open-source forum projects$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2b43eeda-4ceb-459a-a73d-d764275698c6', $q$Requires familiarity with Python/Django for deeper customization$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2b43eeda-4ceb-459a-a73d-d764275698c6', $q$Is Misago free to use?$q$, $q$Yes, Misago is free and open-source software; there is no license fee, only the cost of hosting it yourself.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2b43eeda-4ceb-459a-a73d-d764275698c6', $q$What technology stack does Misago use?$q$, $q$Misago's backend is built on Django (Python) and its frontend uses React (JavaScript).$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2b43eeda-4ceb-459a-a73d-d764275698c6', $q$Who created Misago?$q$, $q$Misago was created by developer RafaЕ‚ PitoЕ„, with the project's history on GitHub dating back to around 2013.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2b43eeda-4ceb-459a-a73d-d764275698c6', $q$How does Misago compare to Discourse?$q$, $q$Both are modern open-source forum platforms; Misago is Django/Python-based and fully self-hosted with no paid hosted tier, while Discourse is Ruby-based and offers both self-hosted and paid managed hosting options.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2b43eeda-4ceb-459a-a73d-d764275698c6', $q$Does Misago support social login?$q$, $q$Yes, it supports OAuth login integration with more than 50 providers including Google, Facebook, GitHub, and Steam.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2b43eeda-4ceb-459a-a73d-d764275698c6', $q$Can Misago handle large communities?$q$, $q$Yes, it supports unlimited categories and subcategories and is designed to be fast and scalable for growing communities.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2b43eeda-4ceb-459a-a73d-d764275698c6', $q$Open-source project communities$q$, $q$Developer-led communities that want a self-hosted, customizable forum tied closely to their own infrastructure.$q$, $q$Open-source maintainers and developer communities$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2b43eeda-4ceb-459a-a73d-d764275698c6', $q$Niche hobbyist forums$q$, $q$Enthusiast communities that want a free, modern discussion board without recurring SaaS fees.$q$, $q$Hobbyist and interest-based communities$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2b43eeda-4ceb-459a-a73d-d764275698c6', $q$Support and Q&A communities$q$, $q$Organizations running product support forums that benefit from best-answer marking and moderation tools.$q$, $q$Software companies and product support teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2b43eeda-4ceb-459a-a73d-d764275698c6', $q$Open Source (Self-Hosted)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full source code","Self-host on your own server","Unlimited categories and subcategories","Moderation and permission tools"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2b43eeda-4ceb-459a-a73d-d764275698c6', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Misago is a free, open-source forum application built on Django (Python) for the backend and React for the frontend, created by developer RafaЕ‚ PitoЕ„ as a modern, self-hosted alternative to legacy and commercial forum software.$q$, $q$The project aims to provide a fast, scalable, and responsive discussion board experience comparable to platforms like Discourse, while remaining fully open source with no paid hosted tier.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2b43eeda-4ceb-459a-a73d-d764275698c6', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Misago supports user registration and profiles with OAuth login through more than 50 providers, Markdown and BBCode post formatting, file attachments with thumbnails, edit history with revision tracking, and a best-answer marking system for Q&A-style discussions.$q$, $q$Administrators can build unlimited categories and nested subcategories, and moderators have access to a full moderation queue, post approval workflows, banning tools by name, email, or IP, and role-based permission controls.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2b43eeda-4ceb-459a-a73d-d764275698c6', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Misago is completely free and open source; there is no license fee to install or run it. Operators are responsible only for their own server hosting and any custom development or support they choose to arrange.$q$, $q$This contrasts with commercial enterprise forum platforms that can cost thousands of dollars per month, making Misago attractive to budget-conscious communities and developers who want full control over their forum's code and data.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('2b43eeda-4ceb-459a-a73d-d764275698c6', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('2b43eeda-4ceb-459a-a73d-d764275698c6', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b56d7d7d-6b4d-47bb-b82f-c7a9036e4a72', $q$Event and attribute data model$q$, $q$Structures threat indicators as events with attributes, enabling consistent, machine-parsable threat data.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b56d7d7d-6b4d-47bb-b82f-c7a9036e4a72', $q$Automatic correlation$q$, $q$Correlates related indicators across events to surface connections analysts might otherwise miss.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b56d7d7d-6b4d-47bb-b82f-c7a9036e4a72', $q$STIX and open standards support$q$, $q$Interoperates with other threat intelligence tools via widely used data exchange standards.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b56d7d7d-6b4d-47bb-b82f-c7a9036e4a72', $q$REST API and PyMISP library$q$, $q$Enables automation and integration with SIEMs and other security infrastructure.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b56d7d7d-6b4d-47bb-b82f-c7a9036e4a72', $q$Community and distribution controls$q$, $q$Fine-grained control over which organizations or communities can see shared intelligence.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b56d7d7d-6b4d-47bb-b82f-c7a9036e4a72', $q$Peer-to-peer synchronization$q$, $q$Instances can sync threat data with trusted partner organizations automatically.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b56d7d7d-6b4d-47bb-b82f-c7a9036e4a72', $q$Taxonomies and tagging$q$, $q$Standardized tagging for classifying and filtering threat data consistently.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b56d7d7d-6b4d-47bb-b82f-c7a9036e4a72', $q$Curated feeds and communities$q$, $q$Subscribe to external, vetted threat intelligence feeds and sharing communities.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b56d7d7d-6b4d-47bb-b82f-c7a9036e4a72', $q$Free and open source with no license fees$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b56d7d7d-6b4d-47bb-b82f-c7a9036e4a72', $q$Widely adopted as a de facto standard among CERTs, government agencies, and SOCs$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b56d7d7d-6b4d-47bb-b82f-c7a9036e4a72', $q$Strong correlation engine for connecting related threat indicators$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b56d7d7d-6b4d-47bb-b82f-c7a9036e4a72', $q$Extensive integration options via REST API and PyMISP$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b56d7d7d-6b4d-47bb-b82f-c7a9036e4a72', $q$Active international community and ongoing EU-supported development$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b56d7d7d-6b4d-47bb-b82f-c7a9036e4a72', $q$Requires self-hosting and security operations expertise to deploy and maintain$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b56d7d7d-6b4d-47bb-b82f-c7a9036e4a72', $q$User interface and onboarding can be complex for newcomers compared to modern commercial TIPs$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b56d7d7d-6b4d-47bb-b82f-c7a9036e4a72', $q$No official vendor SLA or dedicated commercial support from the core project itself$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b56d7d7d-6b4d-47bb-b82f-c7a9036e4a72', $q$Data quality depends heavily on the communities and feeds an organization chooses to trust$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b56d7d7d-6b4d-47bb-b82f-c7a9036e4a72', $q$Scaling and performance tuning for very large deployments requires specialized knowledge$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b56d7d7d-6b4d-47bb-b82f-c7a9036e4a72', $q$What does MISP stand for?$q$, $q$MISP originally stood for Malware Information Sharing Platform and is now commonly referred to as an open-source threat intelligence platform.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b56d7d7d-6b4d-47bb-b82f-c7a9036e4a72', $q$Is MISP free?$q$, $q$Yes, MISP is free and open-source software released under the AGPL license, with no vendor license fee.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b56d7d7d-6b4d-47bb-b82f-c7a9036e4a72', $q$Who maintains MISP?$q$, $q$MISP is primarily maintained by CIRCL, the Computer Incident Response Center Luxembourg, along with contributors from Belgian Defence, NATO NCIRC, and an international open-source community.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b56d7d7d-6b4d-47bb-b82f-c7a9036e4a72', $q$What kind of organizations use MISP?$q$, $q$Security operations centers, CERTs/CSIRTs, government cybersecurity agencies, financial sector ISACs, and enterprise threat intelligence teams commonly use MISP.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b56d7d7d-6b4d-47bb-b82f-c7a9036e4a72', $q$Does MISP support automation and integrations?$q$, $q$Yes, it provides a REST API and the PyMISP Python library for integrating with SIEMs and other security tooling.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b56d7d7d-6b4d-47bb-b82f-c7a9036e4a72', $q$What are alternatives to MISP?$q$, $q$Common alternatives include OpenCTI, Anomali, ThreatConnect, and Recorded Future, though MISP is distinguished by being fully free, open source, and community-governed.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b56d7d7d-6b4d-47bb-b82f-c7a9036e4a72', $q$National CERT threat sharing$q$, $q$Government CERTs and CSIRTs use MISP to share indicators of compromise with national and international partners.$q$, $q$Government cybersecurity agencies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b56d7d7d-6b4d-47bb-b82f-c7a9036e4a72', $q$SOC threat intelligence correlation$q$, $q$Security operations centers ingest and correlate threat feeds to detect and respond to attacks faster.$q$, $q$Enterprise security operations teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b56d7d7d-6b4d-47bb-b82f-c7a9036e4a72', $q$Sector-based intelligence sharing$q$, $q$Industry groups such as financial-sector ISACs use MISP communities to share sector-specific threat data.$q$, $q$Financial services and critical infrastructure organizations$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b56d7d7d-6b4d-47bb-b82f-c7a9036e4a72', $q$Open Source (Self-Hosted)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full source code under AGPL","Self-host on your own infrastructure","REST API and PyMISP access","Access to public MISP communities and feeds"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b56d7d7d-6b4d-47bb-b82f-c7a9036e4a72', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$MISP is a free, open-source threat intelligence platform used to collect, store, correlate, and share cybersecurity indicators of compromise and other threat data between organizations. The project began around 2011, created by developer Christophe Vandeplas to solve the problem of threat indicators being shared informally via email or unstructured documents rather than machine-parsable formats.$q$, $q$Today MISP is developed and maintained primarily by CIRCL, the Computer Incident Response Center Luxembourg, together with contributors from Belgian Defence, NATO's NCIRC, and an international open-source community, with funding support that has included the European Union's Connecting Europe Facility program.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b56d7d7d-6b4d-47bb-b82f-c7a9036e4a72', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$MISP structures threat data as events and attributes, automatically correlating related indicators across the platform and supporting tagging via taxonomies for consistent classification. It supports open standards such as STIX for interoperability and provides a REST API plus the PyMISP Python library for automating integrations with SIEMs and other security tools.$q$, $q$Organizations can control who sees shared intelligence through community and organization-based access controls and distribution levels, and can synchronize with trusted partners or subscribe to curated public MISP feeds and communities for external threat data.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b56d7d7d-6b4d-47bb-b82f-c7a9036e4a72', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$MISP is released under the AGPL open-source license and is free to download, self-host, and modify, with no vendor license fee. Costs are limited to whatever infrastructure an organization uses to host its own instance.$q$, $q$A broader ecosystem exists around MISP including free public threat-sharing communities and commercial vendors that offer managed MISP hosting, integration, or support services for organizations that prefer not to operate the platform themselves.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b56d7d7d-6b4d-47bb-b82f-c7a9036e4a72', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b56d7d7d-6b4d-47bb-b82f-c7a9036e4a72', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2e0ce45d-dae1-4d7d-8c4b-eae668045f9e', $q$Shared team inbox$q$, $q$Multiple teammates can view, discuss, and respond to the same email, SMS, or social conversations from one shared address.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2e0ce45d-dae1-4d7d-8c4b-eae668045f9e', $q$In-thread internal chat$q$, $q$Real-time team chat embedded directly inside email conversations for discussing how to respond.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2e0ce45d-dae1-4d7d-8c4b-eae668045f9e', $q$Shared draft collaboration$q$, $q$Teammates can see each other typing a reply in real time before it's sent.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2e0ce45d-dae1-4d7d-8c4b-eae668045f9e', $q$Conversation assignment and tagging$q$, $q$Assign conversations to specific team members and organize them with labels.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2e0ce45d-dae1-4d7d-8c4b-eae668045f9e', $q$Tasks tied to conversations$q$, $q$Turn emails or messages into trackable tasks without leaving the conversation.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2e0ce45d-dae1-4d7d-8c4b-eae668045f9e', $q$Automation rules$q$, $q$Automatically route, label, or assign incoming messages based on custom rules.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2e0ce45d-dae1-4d7d-8c4b-eae668045f9e', $q$Multi-channel support$q$, $q$Manage email, SMS, and social/messaging accounts from a single shared inbox app.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2e0ce45d-dae1-4d7d-8c4b-eae668045f9e', $q$AI-assisted drafting$q$, $q$AI features help draft replies faster on eligible plans.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2e0ce45d-dae1-4d7d-8c4b-eae668045f9e', $q$Combines shared inbox and internal team chat in one native app$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2e0ce45d-dae1-4d7d-8c4b-eae668045f9e', $q$Bootstrapped, profitable company independent of VC pressure$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2e0ce45d-dae1-4d7d-8c4b-eae668045f9e', $q$Free plan available for very small teams$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2e0ce45d-dae1-4d7d-8c4b-eae668045f9e', $q$Multi-channel support beyond just email, including SMS and social accounts$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2e0ce45d-dae1-4d7d-8c4b-eae668045f9e', $q$Real-time shared draft visibility reduces duplicate replies$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2e0ce45d-dae1-4d7d-8c4b-eae668045f9e', $q$Per-user pricing can add up for larger teams compared to some flat-rate alternatives$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2e0ce45d-dae1-4d7d-8c4b-eae668045f9e', $q$Free plan is limited to just 3 users$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2e0ce45d-dae1-4d7d-8c4b-eae668045f9e', $q$Higher-tier features like SSO and advanced analytics are gated behind the most expensive plan$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2e0ce45d-dae1-4d7d-8c4b-eae668045f9e', $q$Primarily desktop/web and mobile app focused, without the extensive third-party app marketplace some competitors offer$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2e0ce45d-dae1-4d7d-8c4b-eae668045f9e', $q$Best value requires annual billing; monthly billing costs more per seat$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2e0ce45d-dae1-4d7d-8c4b-eae668045f9e', $q$What is Missive used for?$q$, $q$Missive is used as a shared team inbox and internal chat tool, letting multiple people collaborate on shared email, SMS, and social message accounts from one app.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2e0ce45d-dae1-4d7d-8c4b-eae668045f9e', $q$Is Missive free?$q$, $q$Missive offers a free plan for teams of up to 3 users; paid plans start at $14 per user per month billed yearly.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2e0ce45d-dae1-4d7d-8c4b-eae668045f9e', $q$Who founded Missive?$q$, $q$Missive was founded in 2015 in Quebec City, Canada, by Philippe Lehoux, Etienne Lemay, and Rafael Masson.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2e0ce45d-dae1-4d7d-8c4b-eae668045f9e', $q$Does Missive have internal team chat?$q$, $q$Yes, Missive embeds real-time internal chat directly inside email threads so teams can discuss responses without leaving the conversation.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2e0ce45d-dae1-4d7d-8c4b-eae668045f9e', $q$How is Missive different from Slack or Gmail?$q$, $q$Unlike Slack, Missive is built around shared inboxes for email/SMS/social conversations rather than general team messaging, and unlike Gmail, it adds native internal chat, task management, and multi-user collaboration on the same inbox.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2e0ce45d-dae1-4d7d-8c4b-eae668045f9e', $q$Does Missive offer a free trial for paid plans?$q$, $q$Yes, all paid plans include a 30-day free trial with no credit card required.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2e0ce45d-dae1-4d7d-8c4b-eae668045f9e', $q$Customer support teams$q$, $q$Support teams sharing a support@ inbox can assign, discuss, and resolve tickets collaboratively.$q$, $q$Customer support and helpdesk teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2e0ce45d-dae1-4d7d-8c4b-eae668045f9e', $q$Sales team inbox management$q$, $q$Sales teams sharing a common sales@ address can coordinate follow-ups and avoid duplicate replies.$q$, $q$Sales teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2e0ce45d-dae1-4d7d-8c4b-eae668045f9e', $q$Small business operations$q$, $q$Small companies managing multiple shared addresses and channels without a dedicated helpdesk system.$q$, $q$Small and mid-sized businesses$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2e0ce45d-dae1-4d7d-8c4b-eae668045f9e', $q$Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["Up to 3 users","Core shared inbox","Internal chat"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2e0ce45d-dae1-4d7d-8c4b-eae668045f9e', $q$Starter$q$, $q$$14/user/month (billed yearly)$q$, $q$Annual (monthly available at higher rate)$q$, NULL, $q$["Up to 5 users","One shared inbox","Internal chat within email threads","Basic rules and integrations"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2e0ce45d-dae1-4d7d-8c4b-eae668045f9e', $q$Productive$q$, $q$$24/user/month (billed yearly)$q$, $q$Annual (monthly available at higher rate)$q$, NULL, $q$["Up to 50 users","Unlimited shared inboxes","Advanced automation rules (up to 1000)","Basic analytics and reporting","API access"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2e0ce45d-dae1-4d7d-8c4b-eae668045f9e', $q$Business$q$, $q$$36/user/month (billed yearly)$q$, $q$Annual (monthly available at higher rate)$q$, NULL, $q$["Unlimited users","SAML SSO","IP restrictions","Advanced analytics and reporting","Personalized onboarding"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2e0ce45d-dae1-4d7d-8c4b-eae668045f9e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Missive is a shared team inbox and internal chat platform designed for teams that collaborate around email, SMS, and social messages. Founded in 2015 in Quebec City, Canada, by Philippe Lehoux, Etienne Lemay, and Rafael Masson, the company is fully bootstrapped without venture capital funding.$q$, $q$The product's core idea is to combine a shared inbox with real-time internal team chat embedded directly inside email threads, letting teammates coordinate on responses without switching to a separate messaging app.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2e0ce45d-dae1-4d7d-8c4b-eae668045f9e', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Missive supports shared email, SMS, and social accounts, conversation assignment and tagging, shared draft collaboration where teammates can see each other typing responses in real time, and tasks tied directly to conversations.$q$, $q$Higher tiers add automation rules for routing and labeling messages, integrations with external tools, an API for custom workflows, AI-assisted drafting, and analytics/reporting for team performance.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2e0ce45d-dae1-4d7d-8c4b-eae668045f9e', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Missive offers a free plan for teams of up to 3 users with core shared-inbox and chat features. Paid plans are Starter at $14 per user per month (up to 5 users), Productive at $24 per user per month (up to 50 users), and Business at $36 per user per month (unlimited users), all billed yearly with monthly billing also available.$q$, $q$Every paid plan includes a 30-day free trial with no credit card required, and pricing scales with added features like unlimited shared inboxes, advanced automation, SSO, and priority support at higher tiers.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bbcea426-8b22-4fd5-96ad-4e11c6da8bd2', $q$ActivityPub federation$q$, $q$Interoperates with other Fediverse platforms like Mastodon, letting users on different servers follow and interact with each other.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bbcea426-8b22-4fd5-96ad-4e11c6da8bd2', $q$Custom emoji reactions$q$, $q$Users react to notes with custom emoji rather than a simple like button, a signature Misskey interaction model.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bbcea426-8b22-4fd5-96ad-4e11c6da8bd2', $q$Channels$q$, $q$Topic-based discussion spaces within an instance for organizing conversations by subject.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bbcea426-8b22-4fd5-96ad-4e11c6da8bd2', $q$Antennas$q$, $q$Custom timelines built from specific keywords, users, or lists for tracking topics of interest.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bbcea426-8b22-4fd5-96ad-4e11c6da8bd2', $q$Drive file management$q$, $q$A built-in file manager for organizing images, videos, and other uploads.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bbcea426-8b22-4fd5-96ad-4e11c6da8bd2', $q$Extensive UI theming$q$, $q$Deep customization of the interface's appearance and layout.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bbcea426-8b22-4fd5-96ad-4e11c6da8bd2', $q$Configurable user roles$q$, $q$Instance admins can define custom roles and permissions for users.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bbcea426-8b22-4fd5-96ad-4e11c6da8bd2', $q$Long-form notes$q$, $q$Supports post lengths up to roughly 3,000 characters by default, longer than traditional microblogging limits.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bbcea426-8b22-4fd5-96ad-4e11c6da8bd2', $q$Free and open source under AGPLv3 with no vendor lock-in$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bbcea426-8b22-4fd5-96ad-4e11c6da8bd2', $q$Decentralized architecture avoids reliance on a single company or server$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bbcea426-8b22-4fd5-96ad-4e11c6da8bd2', $q$Distinctive, expressive interaction model with custom emoji reactions$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bbcea426-8b22-4fd5-96ad-4e11c6da8bd2', $q$Highly customizable UI, themes, and user roles$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bbcea426-8b22-4fd5-96ad-4e11c6da8bd2', $q$Strong, active community, especially in the Japanese Fediverse$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bbcea426-8b22-4fd5-96ad-4e11c6da8bd2', $q$Running your own instance requires server administration knowledge$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bbcea426-8b22-4fd5-96ad-4e11c6da8bd2', $q$Fragmented ecosystem across many independent instances can be confusing for new users$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bbcea426-8b22-4fd5-96ad-4e11c6da8bd2', $q$No official company support or SLA since it is community-maintained$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bbcea426-8b22-4fd5-96ad-4e11c6da8bd2', $q$Content moderation quality varies significantly between instances$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bbcea426-8b22-4fd5-96ad-4e11c6da8bd2', $q$Feature set and terminology (notes, antennas, drive) differ from mainstream social apps, adding a learning curve$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bbcea426-8b22-4fd5-96ad-4e11c6da8bd2', $q$What is Misskey?$q$, $q$Misskey is a free, open-source, decentralized microblogging platform that is part of the Fediverse, using the ActivityPub protocol to federate with other servers like Mastodon.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bbcea426-8b22-4fd5-96ad-4e11c6da8bd2', $q$Who created Misskey?$q$, $q$Misskey was created in 2014 by Japanese developer Eiji Shinoda, known online as syuilo.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bbcea426-8b22-4fd5-96ad-4e11c6da8bd2', $q$Is Misskey free?$q$, $q$Yes, Misskey is free, open-source software released under the AGPLv3 license; joining a public instance is typically free, and self-hosting costs only your own server infrastructure.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bbcea426-8b22-4fd5-96ad-4e11c6da8bd2', $q$How is Misskey different from Mastodon?$q$, $q$Both are Fediverse platforms using ActivityPub, but Misskey has a distinct feature set including custom emoji reactions, channels, antennas, and a Drive file manager, along with strong roots in the Japanese Fediverse community.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bbcea426-8b22-4fd5-96ad-4e11c6da8bd2', $q$What is the character limit for posts on Misskey?$q$, $q$Posts, called notes, default to up to roughly 3,000 characters, though this limit can be customized by individual instance administrators.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bbcea426-8b22-4fd5-96ad-4e11c6da8bd2', $q$Can I run my own Misskey server?$q$, $q$Yes, Misskey is self-hostable open-source software, and anyone can deploy their own instance and federate with the wider Fediverse.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bbcea426-8b22-4fd5-96ad-4e11c6da8bd2', $q$Decentralized social networking$q$, $q$Users seeking an alternative to centralized platforms like Twitter/X who want a federated, community-run experience.$q$, $q$Privacy- and decentralization-minded social media users$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bbcea426-8b22-4fd5-96ad-4e11c6da8bd2', $q$Niche and interest-based communities$q$, $q$Groups running their own themed instance with custom moderation and branding.$q$, $q$Online communities and interest groups$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bbcea426-8b22-4fd5-96ad-4e11c6da8bd2', $q$Japanese-language Fediverse participation$q$, $q$Users and communities engaging in Japan's particularly active Misskey and Fediverse ecosystem.$q$, $q$Japanese-speaking social media users$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bbcea426-8b22-4fd5-96ad-4e11c6da8bd2', $q$Public Instance (e.g. misskey.io)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Join an existing federated instance","Full note and reaction features","No self-hosting required"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bbcea426-8b22-4fd5-96ad-4e11c6da8bd2', $q$Self-Hosted Instance$q$, $q$Free (software); hosting costs apply$q$, $q$N/A$q$, NULL, $q$["Full source code under AGPLv3","Complete control over moderation and customization","Federates with the wider Fediverse"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bbcea426-8b22-4fd5-96ad-4e11c6da8bd2', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Misskey is a free, open-source, decentralized microblogging platform that is part of the Fediverse, the network of federated social servers connected via the ActivityPub protocol. It was created in 2014 by Japanese developer Eiji Shinoda (syuilo), initially as a BBS-style forum, later evolving into a microblogging platform after adding a timeline feature.$q$, $q$In 2018 Misskey adopted ActivityPub, enabling federation with other platforms such as Mastodon, and its flagship instance misskey.io launched in April 2019, later becoming one of the largest hubs of the Japanese-language Fediverse.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bbcea426-8b22-4fd5-96ad-4e11c6da8bd2', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Posts on Misskey, called notes, support up to roughly 3,000 characters by default (configurable per instance) along with images, videos, audio, and polls. The platform is distinguished by custom emoji reactions rather than simple likes, topic-based channels, and antennas for building custom keyword- or account-based timelines.$q$, $q$Additional features include a built-in Drive for managing uploaded files, extensive UI theming and customization, configurable user roles and permissions, and a responsive Progressive Web App interface, all developed in TypeScript under the AGPLv3 open-source license.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bbcea426-8b22-4fd5-96ad-4e11c6da8bd2', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Misskey itself is free, open-source software with no vendor pricing model; anyone can self-host an instance at their own infrastructure cost. Joining an existing public instance such as misskey.io is typically free for end users.$q$, $q$Because there is no central company selling Misskey, costs vary entirely based on whether a user joins an existing free instance or chooses to run and maintain their own server.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('bbcea426-8b22-4fd5-96ad-4e11c6da8bd2', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('bbcea426-8b22-4fd5-96ad-4e11c6da8bd2', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f4959893-76cd-46a8-ac09-5ec52854907c', $q$Broad protocol support$q$, $q$Supports HLS, MPEG-DASH, RTMP, WebRTC, SRT, and other streaming protocols for both ingest and output.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f4959893-76cd-46a8-ac09-5ec52854907c', $q$Public-domain licensing$q$, $q$Fully open source under a public-domain dedication (with Zero-Clause BSD fallback), free for any use including commercial.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f4959893-76cd-46a8-ac09-5ec52854907c', $q$Live and on-demand streaming$q$, $q$Handles both live broadcast workflows and video-on-demand delivery within the same toolkit.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f4959893-76cd-46a8-ac09-5ec52854907c', $q$Modular architecture$q$, $q$Components can be combined to build custom streaming pipelines suited to specific infrastructure needs.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f4959893-76cd-46a8-ac09-5ec52854907c', $q$Transcoding support$q$, $q$Can transcode streams to different formats and bitrates as part of the delivery pipeline.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f4959893-76cd-46a8-ac09-5ec52854907c', $q$No per-server or per-feature limits$q$, $q$All features are available without artificial software-imposed restrictions.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f4959893-76cd-46a8-ac09-5ec52854907c', $q$Optional professional services$q$, $q$SLAs, technical assistance, and custom development available from the maintaining team for a fee.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f4959893-76cd-46a8-ac09-5ec52854907c', $q$Fully public-domain licensed, free for any use including commercial$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f4959893-76cd-46a8-ac09-5ec52854907c', $q$Wide protocol support covering nearly every major streaming standard$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f4959893-76cd-46a8-ac09-5ec52854907c', $q$No artificial feature gating or per-server licensing costs$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f4959893-76cd-46a8-ac09-5ec52854907c', $q$Cooperative ownership model with an experienced founding team$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f4959893-76cd-46a8-ac09-5ec52854907c', $q$Suitable for building custom, high-performance streaming infrastructure$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f4959893-76cd-46a8-ac09-5ec52854907c', $q$Requires technical expertise to deploy, configure, and maintain compared to managed streaming SaaS products$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f4959893-76cd-46a8-ac09-5ec52854907c', $q$No fixed public pricing for professional support services; requires contacting sales$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f4959893-76cd-46a8-ac09-5ec52854907c', $q$Smaller community and ecosystem compared to some commercial streaming platforms$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f4959893-76cd-46a8-ac09-5ec52854907c', $q$Historical documentation still references older mixed open/proprietary licensing that no longer fully applies$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f4959893-76cd-46a8-ac09-5ec52854907c', $q$Best suited to organizations building their own infrastructure rather than those wanting an out-of-the-box hosted solution$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f4959893-76cd-46a8-ac09-5ec52854907c', $q$Is MistServer free?$q$, $q$Yes, the entire MistServer codebase has been fully open source and public domain since 2022, free to use for any purpose including commercial use, with optional paid professional services available separately.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f4959893-76cd-46a8-ac09-5ec52854907c', $q$What protocols does MistServer support?$q$, $q$MistServer supports a wide range of streaming protocols including HLS, MPEG-DASH, RTMP, WebRTC, and SRT, among others, for both ingest and output.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f4959893-76cd-46a8-ac09-5ec52854907c', $q$Who created MistServer?$q$, $q$MistServer originated from Dutch company DDVTech B.V., founded in 2009, and is now maintained by OptiMist Video B.V., a cooperative formed by the original team after a 2021-2022 acquisition and public-domain release by Livepeer.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f4959893-76cd-46a8-ac09-5ec52854907c', $q$Can I use MistServer commercially for free?$q$, $q$Yes, since the 2022 public-domain release with MistServer 3.0, all features can be used commercially with no software-imposed licensing fees.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f4959893-76cd-46a8-ac09-5ec52854907c', $q$Does MistServer offer paid support?$q$, $q$Yes, the maintaining team offers optional professional services such as SLAs, technical assistance, and custom development for a fee, with current pricing available on request.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f4959893-76cd-46a8-ac09-5ec52854907c', $q$What is MistServer used for?$q$, $q$It is used to build custom live-streaming and video-on-demand infrastructure, including broadcast platforms and CDNs, by broadcasters, media companies, and developers.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f4959893-76cd-46a8-ac09-5ec52854907c', $q$Custom live-streaming platforms$q$, $q$Developers building their own branded streaming service that needs broad protocol support.$q$, $q$Streaming platform developers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f4959893-76cd-46a8-ac09-5ec52854907c', $q$Broadcast and media workflows$q$, $q$Broadcasters and media companies needing flexible ingest and delivery across multiple protocols.$q$, $q$Broadcasters and media companies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f4959893-76cd-46a8-ac09-5ec52854907c', $q$Video-on-demand infrastructure$q$, $q$Organizations building VOD delivery pipelines without relying on a closed commercial CDN product.$q$, $q$Video infrastructure and DevOps teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f4959893-76cd-46a8-ac09-5ec52854907c', $q$Open Source (Public Domain)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full feature set","Free for commercial use","No per-server restrictions","Public-domain/Zero-Clause BSD licensing"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f4959893-76cd-46a8-ac09-5ec52854907c', $q$Professional Services$q$, $q$Custom (contact sales)$q$, $q$Monthly service charge or custom agreement$q$, NULL, $q$["SLAs","Technical assistance","Custom feature development"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f4959893-76cd-46a8-ac09-5ec52854907c', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$MistServer is a media streaming server toolkit built to ingest, transcode, and deliver live and on-demand video across a wide range of protocols, including HLS, MPEG-DASH, RTMP, WebRTC, and SRT. Its roots trace back to 2009, when Dutch company DDVTech B.V. was founded after a failed media project exposed shortcomings in existing streaming server software.$q$, $q$After a 2021 acquisition by Livepeer, Inc., the entire MistServer codebase was released into the public domain in 2022 with the launch of version 3.0, and the original team restructured as a cooperative, OptiMist Video B.V., with each team member an equal part-owner.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f4959893-76cd-46a8-ac09-5ec52854907c', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$MistServer functions as a modular toolkit that can accept input via numerous streaming protocols and output to numerous player-facing protocols simultaneously, making it suitable for building custom live-streaming platforms, video-on-demand services, CDNs, and broadcast workflows.$q$, $q$Because it is public-domain software, every feature is free to use for any purpose, including commercial use, with no per-server or per-feature restrictions imposed by the software itself.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f4959893-76cd-46a8-ac09-5ec52854907c', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The core MistServer software is entirely free, full-featured, and usable for any purpose, including commercial use, with no software-imposed restrictions since its full open-sourcing in 2022.$q$, $q$The team behind MistServer also offers optional paid professional services on top of the free core, such as SLAs, technical assistance, and custom feature or build development, typically arranged as a simple monthly service charge or custom licensing agreement, with current pricing available by contacting their sales team.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f4959893-76cd-46a8-ac09-5ec52854907c', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
